import React from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import './style.css';

export default function CounterDetailsPage() {
  const navigate = useNavigate();
  const { value } = useParams();

  return (
    <main className="counter-details-page">
      <section className="counter-details-card">
        <p className="counter-details-kicker">Router Demo</p>
        <h1>Counter Details</h1>
        <p className="counter-details-text">
          This page reads the number from the URL using <code>useParams</code>.
        </p>

        <div className="counter-details-value">{value}</div>

        <div className="counter-details-actions">
          <button type="button" className="counter-details-button primary" onClick={() => navigate('/counters')}>
            Back To Counters
          </button>
          <button type="button" className="counter-details-button secondary" onClick={() => navigate(-1)}>
            Go Back
          </button>
        </div>
      </section>
    </main>
  );
}
